mapper.sql:
SELECT DISTINCT MST.SEQ ,MST.CUSTOMER_ID ,CUS.CUSTOMER_LINK_NAME ,MST.CHNL_CD ,(SELECT DTL_CD_NM FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'UsimReqChnlCd' AND DTL_CD = MST.CHNL_CD) AS CHNL_NM ,MST.REQ_QNTY ,MST.DLVRY_NAME ,MST.DLVRY_TEL_FN || '-' || MST.DLVRY_TEL_MN || '-' || MST.DLVRY_TEL_RN AS DLVRY_TEL ,MST.DLVRY_POST ,MST.DLVRY_ADDR || ' ' || MST.DLVRY_ADDR_DTL AS DLVRY_ADDR ,MST.DLVRY_ADDR_DTL ,MST.DLVRY_MEMO ,(SELECT DTL_CD_NM FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'PERCEL' AND DTL_CD = MST.TB_CD) AS TB_NM ,MST.DLVRY_NO ,MST.STATUS ,(SELECT DTL_CD_NM FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'UsimReqStatus' AND DTL_CD = MST.STATUS) AS STATUS_NM ,MST.PROC_YN ,FN_GET_CODENM('CMN0084', NVL(MST.PROC_YN, 'N')) AS PROC_YN_NM ,MST.PROC_MEMO ,TO_CHAR(MST.PROC_DTTM, 'YYYY-MM-DD HH24:MI:SS') AS PROC_DTTM ,TO_CHAR(MST.REQ_IN_DAY, 'YYYY-MM-DD') AS REQ_IN_DAY ,TO_CHAR(MST.REQ_IN_DAY, 'HH24:MI:SS') AS REQ_IN_TIME FROM NMCP_FREE_USIM_REQ_MST@DL_MCP MST ,NMCP_FREE_USIM_REQ_DTL@DL_MCP DTL ,MSP_JUO_SUB_INFO SUB ,MSP_JUO_CUS_INFO CUS WHERE MST.SEQ = DTL.SEQ AND DTL.CONTRACT_NUM = SUB.CONTRACT_NUM AND MST.CUSTOMER_ID = CUS.CUSTOMER_ID
AND TO_CHAR(MST.REQ_IN_DAY, 'YYYYMMDD') BETWEEN #{srchStrtDt} AND #{srchEndDt}
AND SUB.CONTRACT_NUM = #{searchName}
AND UPPER(CUS.CUSTOMER_LINK_NAME) LIKE UPPER(#{searchName}) || '%'
AND SUB.SUBSCRIBER_NO = #{searchName}
AND MST.DLVRY_TEL_FN || MST.DLVRY_TEL_MN || MST.DLVRY_TEL_RN = translate(#{searchName},'1234567890-','1234567890')
AND MST.DLVRY_NO = #{searchName}
AND NVL(MST.PROC_YN, 'N') = #{procYn}
AND MST.STATUS = #{status}
AND MST.CHNL_CD = #{chnlCd}
AND MST.DLVRY_NO IS NOT NULL
AND MST.DLVRY_NO IS NULL
AND ( DTL.NFC_USIM_YN = #{nfcUsimYn}
OR DTL.NFC_USIM_YN IS NULL
)
ORDER BY MST.SEQ DESC

