/*UsimDlvryChangeMapper.selectUsimChangeDtlListExcel*/ SELECT MST.SEQ ,(SELECT DTL_CD_NM FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'UsimReqChnlCd' AND DTL_CD = MST.CHNL_CD) AS CHNL_NM ,DTL.CONTRACT_NUM ,CUS.CUSTOMER_LINK_NAME ,MST.REQ_QNTY || '-' || DTL.SUB_SEQ AS REQ_QNTY ,TO_CHAR(MST.REQ_IN_DAY, 'YYYY-MM-DD') AS REQ_IN_DAY ,TO_CHAR(MST.REQ_IN_DAY, 'HH24:MI:SS') AS REQ_IN_TIME ,DTL.PRDT_CODE ,DTL.USIM_SN ,DTL.CHG_YN ,TO_CHAR(TO_DATE(DTL.CHG_DTTM,'YYYYMMDDHH24MISS'),'YYYY-MM-DD HH24:MI:SS') AS CHG_DTTM ,DECODE(DTL.APPLY_RSLT_CD, NULL, NULL, '00', '성공', '실패') AS APPLY_RSLT_CD ,DTL.APPLY_RSLT_MSG FROM NMCP_FREE_USIM_REQ_MST@DL_MCP MST ,NMCP_FREE_USIM_REQ_DTL@DL_MCP DTL ,MSP_JUO_CUS_INFO CUS ,MSP_JUO_SUB_INFO SUB WHERE MST.SEQ = DTL.SEQ AND DTL.CONTRACT_NUM = SUB.CONTRACT_NUM AND MST.CUSTOMER_ID = CUS.CUSTOMER_ID
AND TO_CHAR(MST.REQ_IN_DAY, 'YYYYMMDD') BETWEEN #{srchStrtDt} AND #{srchEndDt}
AND SUB.CONTRACT_NUM = #{searchName}
AND UPPER(CUS.CUSTOMER_LINK_NAME) LIKE UPPER(#{searchName}) || '%'
AND SUB.SUBSCRIBER_NO = #{searchName}
AND MST.DLVRY_TEL_FN || MST.DLVRY_TEL_MN || MST.DLVRY_TEL_RN = translate(#{searchName},'1234567890-','1234567890')
AND MST.DLVRY_NO = #{searchName}
AND NVL(MST.PROC_YN, 'N') = #{procYn}
AND MST.STATUS = #{status}
AND MST.CHNL_CD = #{chnlCd}
AND MST.DLVRY_NO IS NOT NULL
AND MST.DLVRY_NO IS NULL
AND ( DTL.NFC_USIM_YN = #{nfcUsimYn}
OR DTL.NFC_USIM_YN IS NULL
)
ORDER BY MST.SEQ DESC, DTL.SUB_SEQ

/*UsimDlvryChangeMapper.selectUsimChgDlvryExcelTemp*/ SELECT MST.SEQ ,(SELECT DTL_CD_NM FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'UsimReqChnlCd' AND DTL_CD = MST.CHNL_CD) AS CHNL_NM ,DTL.CONTRACT_NUM ,CUS.CUSTOMER_LINK_NAME ,MST.REQ_QNTY || '-' || DTL.SUB_SEQ AS REQ_QNTY ,TO_CHAR(MST.REQ_IN_DAY, 'YYYY-MM-DD') AS REQ_IN_DAY ,TO_CHAR(MST.REQ_IN_DAY, 'HH24:MI:SS') AS REQ_IN_TIME ,MST.PROC_MEMO ,MST.DLVRY_NAME ,MST.DLVRY_POST ,MST.DLVRY_ADDR || ' ' || MST.DLVRY_ADDR_DTL AS DLVRY_ADDR ,MST.DLVRY_TEL_FN || '-' || MST.DLVRY_TEL_MN || '-' || MST.DLVRY_TEL_RN AS DLVRY_TEL ,MST.DLVRY_MEMO ,DTL.PRDT_CODE ,DTL.USIM_SN ,(SELECT DTL_CD_NM FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'PERCEL' AND DTL_CD = MST.TB_CD) AS TB_NM ,MST.DLVRY_NO ,DECODE(DTL.NFC_USIM_YN, 'Y', 'NFC', 'N', '일반', '') AS NFC_USIM_TYPE ,USIM_MODEL_CD FROM NMCP_FREE_USIM_REQ_MST@DL_MCP MST ,NMCP_FREE_USIM_REQ_DTL@DL_MCP DTL ,MSP_JUO_CUS_INFO CUS ,MSP_JUO_SUB_INFO SUB WHERE MST.SEQ = DTL.SEQ AND DTL.CONTRACT_NUM = SUB.CONTRACT_NUM AND MST.CUSTOMER_ID = CUS.CUSTOMER_ID
AND TO_CHAR(MST.REQ_IN_DAY, 'YYYYMMDD') BETWEEN #{srchStrtDt} AND #{srchEndDt}
AND SUB.CONTRACT_NUM = #{searchName}
AND UPPER(CUS.CUSTOMER_LINK_NAME) LIKE UPPER(#{searchName}) || '%'
AND SUB.SUBSCRIBER_NO = #{searchName}
AND MST.DLVRY_TEL_FN || MST.DLVRY_TEL_MN || MST.DLVRY_TEL_RN = translate(#{searchName},'1234567890-','1234567890')
AND MST.DLVRY_NO = #{searchName}
AND NVL(MST.PROC_YN, 'N') = #{procYn}
AND MST.CHNL_CD = #{chnlCd}
AND MST.DLVRY_NO IS NOT NULL
AND MST.DLVRY_NO IS NULL
AND ( DTL.NFC_USIM_YN = #{nfcUsimYn}
OR DTL.NFC_USIM_YN IS NULL
)
ORDER BY MST.SEQ DESC, DTL.SUB_SEQ

mapper.update:
/*UsimDlvryChangeMapper.updateDlvryInfoExcel*/
UPDATE 	NMCP_FREE_USIM_REQ_MST@DL_MCP
SET		AMD_DTTM = SYSDATE
		,AMD_ID = #{sessionUserId}

		,TB_CD = #{tbCd}


		,DLVRY_NO = #{dlvryNo}

WHERE 	SEQ = #{seq}

/*UsimDlvryChangeMapper.updateUsimInfo*/
UPDATE 	NMCP_FREE_USIM_REQ_DTL@DL_MCP
SET		AMD_DTTM = SYSDATE
		,AMD_ID = #{sessionUserId}

			,PRDT_ID = (SELECT PRDT_ID from CMN_INTM_MDL where PRDT_CODE = #{prdtCode} AND ROWNUM = 1)
			,PRDT_CODE = #{prdtCode}


			,USIM_SN = #{usimSn}

WHERE 	SEQ = #{seq}
AND 	CONTRACT_NUM = #{contractNum}

/*UsimDlvryChangeMapper.updateStatusMst*/
UPDATE 	NMCP_FREE_USIM_REQ_MST@DL_MCP
SET		AMD_DTTM = SYSDATE
		,AMD_ID = #{sessionUserId}
		,STATUS = #{status}
WHERE 	SEQ = #{seq}

/*UsimDlvryChangeMapper.updateStatusDtl*/
UPDATE 	NMCP_FREE_USIM_REQ_DTL@DL_MCP
SET		AMD_DTTM = SYSDATE
		,AMD_ID = #{sessionUserId}
		,STATUS = #{status}
WHERE 	SEQ = #{seq}

/*UsimDlvryChangeMapper.updateUsimChgProcExcel*/
UPDATE 	NMCP_FREE_USIM_REQ_MST@DL_MCP
SET		AMD_DTTM = SYSDATE
		,AMD_ID = #{sessionUserId}
		,PROC_YN = CASE WHEN #{procYn} = 'Y' THEN 'Y' ELSE 'N' END
		,PROC_MEMO = #{procMemo}
		,PROC_DTTM = CASE WHEN #{procYn} = 'Y' THEN SYSDATE ELSE NULL END
WHERE 	SEQ = #{seq}

