/*UsimDlvryChangeMapper.selectMspJuoSubInfoByContractNum*/
SELECT 	CUSTOMER_ID
FROM 	MSP_JUO_SUB_INFO
WHERE 	CONTRACT_NUM = #{contractNum}

/*UsimDlvryChangeMapper.selectSeqByContractNum*/
SELECT 	SEQ
FROM 	NMCP_FREE_USIM_REQ_DTL@DL_MCP
WHERE 	CONTRACT_NUM = #{contractNum}

/*UsimDlvryChangeMapper.dupChkByContractNum*/
