mapper.insert:
/*UsimDlvryChangeMapper.insertUsimChangeChk*/
INSERT INTO NMCP_FREE_USIM_REQ_CHK@DL_MCP
(
			CUSTOMER_ID
			,CONTRACT_NUM
			,CHNL_CD
			,REQ_QNTY
			,DLVRY_NAME
			,DLVRY_TEL_FN
			,DLVRY_TEL_MN
			,DLVRY_TEL_RN
			,DLVRY_POST
			,DLVRY_ADDR
			,DLVRY_ADDR_DTL
			,DLVRY_MEMO
			,TB_CD
			,DLVRY_NO
			,REQ_IN_DAY
			,PRDT_ID
			,PRDT_CODE
			,USIM_SN
			,CRET_ID
			,CRET_DTTM
)
VALUES
(
			(SELECT CUSTOMER_ID FROM MSP_JUO_SUB_INFO WHERE CONTRACT_NUM = #{contractNum})
			,#{contractNum}
			,#{chnlCd}
			,#{reqQnty}
			,#{dlvryName}
			,SUBSTR(#{dlvryTel}, 1, 3)
			,CASE WHEN (LENGTH(#{dlvryTel}) = 10) THEN SUBSTR(#{dlvryTel}, 4, 3) ELSE SUBSTR(#{dlvryTel}, 4, 4) END
			,CASE WHEN (LENGTH(#{dlvryTel}) = 10) THEN SUBSTR(#{dlvryTel}, 7, 4) ELSE SUBSTR(#{dlvryTel}, 8, 4) END
			,#{dlvryPost}
			,#{dlvryAddr}
			,#{dlvryAddrDtl}
			,#{dlvryMemo}
			,#{tbCd}
			,#{dlvryNo}
			,TO_DATE(#{reqInDay}, 'YYYYMMDD')
			,(SELECT PRDT_ID FROM CMN_INTM_MDL WHERE PRDT_CODE = #{prdtCode} AND ROWNUM = 1)
			,#{prdtCode}
			,#{usimSn}
			,#{sessionUserId}
			,SYSDATE
)

mapper.select:
/*UsimDlvryChangeMapper.selectCustomerIdList*/
SELECT 	DISTINCT CUSTOMER_ID
FROM 	NMCP_FREE_USIM_REQ_CHK@DL_MCP

/* UsimDlvryChangeMapper.selectUsimChangeSeq */
SELECT	SQ_FREE_USIM_REQ_MST.NEXTVAL@DL_MCP AS seq
FROM 	DUAL

mapper.insert:
/*UsimDlvryChangeMapper.insertUsimChangeMst*/
INSERT INTO  NMCP_FREE_USIM_REQ_MST@DL_MCP
(
			 SEQ
			 ,CUSTOMER_ID
			 ,CHNL_CD
			 ,REQ_QNTY
			 ,DLVRY_NAME
			 ,DLVRY_TEL_FN
			 ,DLVRY_TEL_MN
			 ,DLVRY_TEL_RN
			 ,DLVRY_POST
			 ,DLVRY_ADDR
			 ,DLVRY_ADDR_DTL
			 ,DLVRY_MEMO
			 ,PROC_MEMO
			 ,PROC_YN
			 ,PROC_DTTM
			 ,TB_CD
			 ,DLVRY_NO
			 ,STATUS
			 ,REQ_IN_DAY
			 ,CRET_ID
			 ,CRET_DTTM
			 ,OSST_NO
)
VALUES(
			#{seq}
			,#{customerId}
			,#{chnlCd}
			,#{reqQnty}
			,#{dlvryName}
			,#{dlvryTelFn}
			,#{dlvryTelMn}
			,#{dlvryTelRn}
			,#{dlvryPost}
			,#{dlvryAddr}
			,#{dlvryAddrDtl}
			,#{dlvryMemo}
			,#{procMemo}
			,#{procYn}
	  		,CASE WHEN #{procYn} = 'Y' THEN SYSDATE ELSE NULL END
			,#{tbCd}
			,#{dlvryNo}
			,'REQ'
			,TO_DATE(NVL(#{reqInDay}, TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')), 'YYYYMMDDHH24MISS')
			,#{sessionUserId}
			,SYSDATE
			,#{osstNo}
)

/*UsimDlvryChangeMapper.insertUsimChangeDtl*/
INSERT INTO  NMCP_FREE_USIM_REQ_DTL@DL_MCP
(
			 SEQ
			 ,SUB_SEQ
			 ,CONTRACT_NUM
			 ,PRDT_ID
			 ,PRDT_CODE
			 ,USIM_SN
			 ,STATUS
			 ,CRET_ID
			 ,CRET_DTTM
			 ,PRE_CHK_RSLT_CD
			 ,PRE_CHK_RSLT_MSG
			 ,NFC_USIM_YN
			 ,USIM_MODEL_CD
			 ,USIM_MODEL_ID
)
VALUES(
			#{seq}
			,NVL((SELECT MAX(SUB_SEQ) + 1 FROM NMCP_FREE_USIM_REQ_DTL@DL_MCP WHERE SEQ = #{seq}) ,1)
			,#{contractNum}
			,#{prdtId}
			,#{prdtCode}
			,#{usimSn}
			,'REQ'
			,#{sessionUserId}
			,SYSDATE
			,'00'
			,'처리성공'
			,DECODE(#{nfcUsimType}, 'NFC', 'Y', '일반', 'N', '') 
			,#{usimModelCd}
			,#{usimModelId}
)

/* UsimDlvryChangeMapper.insertOsstHist */
INSERT INTO NMCP_FREE_USIM_OSST@DL_MCP
(			
 			OSST_NO
			,CONTRACT_NUM
			,SVC_CNTR_NO
			,PRGR_STAT_CD
			,NSTEP_GLOBAL_ID
			,RESPONSE_CODE
			,RESPONSE_BASIC
			,RSLT_CD
			,RSLT_MSG
			,OPEN_DT
			,USIM_CHG_DT
			,ACCEPT_DT
			,USIM_TYPE_CD
			,USIM_ONLY_YN
			,CTN_STATUS
			,REGST_ID
			,REGST_DTTM
)
VALUES
(
			#{osstNo}
			,#{contractNum}
			,#{svcCntrNo}
			,#{prgrStatCd}
			,#{globalNo}
			,#{responseCode}
			,#{responseBasic}
			,#{rsltCd}
			,#{rsltMsg}
			,#{openDt}
			,#{usimChgDt}
			,#{acceptDt}
			,#{usimTypeCd}
			,#{usimOnlyYn}
			,#{ctnStatus}
			,#{sessionUserId}
			,SYSDATE
)

