/*UsimDlvryChangeMapper.updateUsimChg*/
UPDATE 	NMCP_FREE_USIM_REQ_MST@DL_MCP
SET		AMD_DTTM = SYSDATE
		,AMD_ID = #{sessionUserId}

		,DLVRY_NAME = #{dlvryName}


		,DLVRY_TEL_FN = #{dlvryTelFn}


		,DLVRY_TEL_MN = #{dlvryTelMn}


		,DLVRY_TEL_RN = #{dlvryTelRn}


		,DLVRY_POST = #{dlvryPost}


		,DLVRY_ADDR = #{dlvryAddr}


		,DLVRY_ADDR_DTL = #{dlvryAddrDtl}

		,DLVRY_MEMO = #{dlvryMemo}			
		,PROC_MEMO = #{procMemo}
		,PROC_YN = #{procYn}
		,PROC_DTTM = CASE WHEN #{procYn} = 'Y' THEN SYSDATE ELSE NULL END
WHERE 	SEQ = #{seq}

