/*UsimDlvryChangeMapper.selectUsimModelData*/
SELECT
	PRDT_CODE
	,DECODE(NFC_USIM_YN, 'Y', 'NFC', 'N', '일반') AS NFC_USIM_TYPE
FROM CMN_INTM_MDL
WHERE RPRS_PRDT_ID = #{intmMdlId}
